use std::collections::HashMap;

struct ConfigParser {
    data: HashMap<String, String>,
}

impl ConfigParser {
    fn new() -> Self {
        ConfigParser { data: HashMap::new() }
    }

    fn parse_simple(key: &str, value_with_comment: &str) -> Result<(), String> {
        let mut parser = ConfigParser::new();
        parser.data.insert(String::from(key), value_with_comment.to_string());
        Ok(())
    }

    fn get_value(&self, key: &str) -> Option<&String> {
        self.data.get(key)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn setup() -> ConfigParser {
        ConfigParser::new()
    }

    #[test]
    fn test_basic_parsing_and_comment_retention() {
        let mut parser = setup();
        let key1 = "api_endpoint";
        let value1 = "https://example.com/v1; // This is the main URL comment";

        ConfigParser::parse_simple(key1, value1).unwrap();

        assert!(parser.data.contains_key("api_endpoint"));
        let retrieved = parser.get_value("api_endpoint").expect("Should find key");

        assert!(retrieved.as_ref().contains(": // This is the main URL comment"));
    }

    #[test]
    fn test_multiple_fields_are_preserved() {
        let mut parser = setup();
        ConfigParser::parse_simple("timeout", "500ms; /* Default timeout value */ ").unwrap();
        ConfigParser::parse_simple("retries", "3; // Max retries allowed").unwrap();

        let retrieved1 = parser.get_value("timeout").expect("Should find timeout");
        let retrieved2 = parser.get_value("retries").expect("Should find retries");

        assert!(retrieved1.as_ref().contains("/* Default timeout value */"));
        assert!(retrieved2.as_ref().contains("// Max retries allowed"));
    }
}

use std::collections::HashMap;
use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
struct Record {
    id: String,
    data_vector: Vec<f32>,
}

struct FeatureStore {
    embeddings: HashMap<String, Vec<f32>>
}

impl FeatureStore {
    fn new() -> Self {
        FeatureStore { embeddings: HashMap::new() }
    }

    fn compute_embedding(&mut self, record: &Record) -> Result<Vec<f32>, String> {
        if record.data_vector.is_empty() {
            return Err(format!("Cannot process record with empty data for ID {}", record.id));
        }

        let embedding: Vec<f32> = record.data_vector.iter().map(|&v| v * 1.05).collect();
        self.embeddings.insert(record.id.clone(), embedding.clone());
        Ok(embedding)
    }

    fn get_all_embeddings(&self) -> &HashMap<String, Vec<f32>> {
        &self.embeddings
    }
}

#[test]
fn test_feature_store_integration() {
    let mut store = FeatureStore::new();

    let record1 = Record { id: "user_123".to_string(), data_vector: vec![0.1, 0.2] };
    let record2 = Record { id: "item_abc".to_string(), data_vector: vec![1.0, 2.0, 3.0] };

    let result1 = store.compute_embedding(&record1);
    assert!(result1.is_ok());

    let result2 = store.compute_embedding(&record2);
    assert!(result2.is_ok());

    let embeddings = store.get_all_embeddings();
    assert_eq!(embeddings.len(), 2);

    if let Some(vec) = embeddings.get("user_123") {
        assert!(*vec == vec![0.105, 0.21]);
    }

    let empty_record = Record { id: "fail".to_string(), data_vector: vec![] };
    let result_err = store.compute_embedding(&empty_record);
    assert!(result_err.is_err());
}

use std::collections::HashMap;
use std::fs::File;
use std::io::{self, prelude::*};

#[derive(Debug)]
struct Record {
    id: String,
    data_field: String,
    timestamp: i64,
}

fn ingest_csv_data(file_path: &str) -> io::Result<Vec<Record>> {
    let mut file = File::open(file_path)?;
    let mut contents = String::new();
    file.read_to_string(&mut contents)?;

    let mut records: Vec<Record> = Vec::new();
    for line in contents.lines() {
        if line.is_empty() { continue; }
        let parts: Vec<&str> = line.split(',').collect();
        if parts.len() < 3 {
            return Err(io::Error::new(io::ErrorKind::InvalidData, "Malformed CSV line"));
        }

        let id = parts[0].to_string();
        let data_field = parts[1].trim().to_string();
        let timestamp = match parts[2].trim().parse::<i64>() {
            Ok(ts) => ts,
            Err(_) => return Err(io::Error::new(io::ErrorKind::InvalidData, "Invalid timestamp format"))
        };

        records.push(Record { id, data_field, timestamp });
    }
    Ok(records)
}

fn main() -> io::Result<()> {
    let test_file = "test_data.csv";
    std::fs::write(test_file, "101,widget_a,1672531200n102,gadget_b,1672617600n103,thing_c,1672704000")?;

    match ingest_csv_data(test_file) {
        Ok(records) => {
            println!("Successfully ingested {} records:", records.len());
            for record in records {
                println!("  ID: {}, Data: {}", record.id, record.data_field);
            }
        }
        Err(e) => {
            eprintln!("Ingestion failed: {}", e);
        }
    }

    std::fs::remove_file(test_file)?; 
    Ok(())
}

use std::collections::HashMap;

struct DataPair {
    id: u32,
    expected_value: String,
}

fn check_data_integrity(actual_map: HashMap<u32, String>, expected_pairs: &[DataPair]) -> Result<(), String> {
    for pair in expected_pairs {
        match actual_map.get(&pair.id) {
            Some(actual_value) => {
                if actual_value != &pair.expected_value {
                    return Err(format!("Mismatch found for ID {}: Expected '{}', but got '{}'", pair.id, pair.expected_value, actual_value));
                }
            }
            None => {
                return Err(format!("Missing data for ID {}. Could not find expected record.", pair.id));
            }
        }
    }
    Ok(())
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct CacheServer {
    storage: Arc<Mutex<HashMap<String, String>>>, 
}

impl CacheServer {
    fn new() -> Self {
        CacheServer { 
            storage: Arc::new(Mutex::new(HashMap::new())) 
        }
    }

    fn set(&self, key: &str, value: &str) -> Result<(), String> {
        let mut storage = self.storage.lock().unwrap();
        storage.insert(key.to_string(), value.to_string());
        Ok(())
    }

    fn get(&self, key: &str) -> Option<String> {
        let storage = self.storage.lock().unwrap();
        storage.get(key).cloned()
    }
}

#[cfg(test)]
mod tests {
    use super::CacheServer;

    #[test]
    fn test_basic_set_and_get() {
        let server = CacheServer::new();
        server.set("user:1", "alice_data").unwrap();

        match server.get("user:1") {
            Some(value) => assert_eq!(value, "alice_data"),
            None => panic!("Key not found after setting"),
        }
    }

    #[test]
    fn test_key_not_found() {
        let server = CacheServer::new();
        assert!(server.get("nonexistent_key").is_none());
    }

    #[test]
    fn test_overwrite_value() {
        let server = CacheServer::new();
        server.set("config", "old_setting").unwrap();
        server.set("config", "new_setting").unwrap();

        match server.get("config") {
            Some(value) => assert_eq!(value, "new_setting"),
            None => panic!("Key unexpectedly cleared"),
        }
    }
}
